#!/usr/bin/env Rscript
suppressPackageStartupMessages({library(data.table);library(jsonlite)})
parse_args<-function(x){o<-list();i<-1L;while(i<=length(x)){k<-sub("^--","",x[i]);if(i==length(x)||startsWith(x[i+1],"--")){o[[k]]<-TRUE;i<-i+1L}else{o[[k]]<-x[i+1];i<-i+2L}};o};a<-parse_args(commandArgs(trailingOnly=TRUE));need<-c("rds","profile","out");miss<-need[!need%in%names(a)];if(length(miss))stop("Missing: ",paste(miss,collapse=", "));dir.create(dirname(a$out),recursive=TRUE,showWarnings=FALSE);obj<-readRDS(a$rds);features<-unique(as.character(rownames(obj)));if(!length(features)&&inherits(obj,"SummarizedExperiment"))features<-unique(as.character(rownames(SummarizedExperiment::assay(obj,1))));if(!length(features))stop("No feature names");profile<-fromJSON(a$profile,simplifyVector=FALSE)
collect<-function(x){v<-unlist(x,use.names=FALSE);unique(v[grepl("^[A-Z0-9][A-Z0-9.-]{1,30}$",v)])};rows<-list();z<-1L
for(scope in c("lineages","rare_cell_rules")){for(nm in names(profile[[scope]])){g<-collect(profile[[scope]][[nm]]);if(!length(g))next;rows[[z]]<-data.table(scope=scope,module=nm,n_markers=length(g),n_present=sum(g%in%features),coverage=sum(g%in%features)/length(g),missing=paste(setdiff(g,features),collapse=","));z<-z+1L}}
d<-rbindlist(rows,fill=TRUE);allg<-unique(unlist(lapply(c(profile$lineages,profile$rare_cell_rules),collect)));coverage<-sum(allg%in%features)/max(1,length(allg));rules<-profile$final_validation;min_features<-as.integer(ifelse(is.null(rules$minimum_features_for_full_validation),10000,rules$minimum_features_for_full_validation));min_cov<-as.numeric(ifelse(is.null(rules$minimum_profile_marker_coverage),.7,rules$minimum_profile_marker_coverage));status<-if(length(features)>=min_features&&coverage>=min_cov)"PASS"else "FAIL_HVG_OR_INCOMPLETE_FEATURE_SCOPE";fwrite(d,sub("[.]json$","_modules.tsv",a$out),sep="\t");write_json(list(status=status,source_rds=normalizePath(a$rds),source_class=class(obj),n_features=length(features),profile_markers=length(allg),profile_markers_present=sum(allg%in%features),profile_marker_coverage=coverage,minimum_features=min_features,minimum_coverage=min_cov,warning="Absent markers from an HVG/incomplete object are unassayed for final validation and cannot be used as negative evidence."),a$out,pretty=TRUE,auto_unbox=TRUE);cat(readLines(a$out),sep="\n")
